        enrollment_id
      , payment_key
      , order_id
      , order_name
      , amount
      , method
      , status
      , paid_at
) VALUES (
        #{enrollmentId}
      , #{paymentKey}
      , #{orderId}
      , #{orderName}
      , #{amount}
      , #{method}
      , #{status}
      , #{paidAt}
)

